+  private getCursorPagination(opts: CrudOptions) {
+    if (opts.cursor !== undefined && !opts.orderBy) {
+      throw new BadRequestException('cursor requires orderBy');
+    }
+    if (opts.cursor !== undefined && opts.offset !== undefined) {
+      throw new BadRequestException('cursor cannot be used with offset');
+    }
+    if (!opts.orderBy || !opts.limit) {
+      return null;
+    }
+
+    const orderBy = this.getCursorOrderBy(opts.orderBy);
+    const sort = orderBy
+      .map(([field, direction]) => `${field}:${direction}`)
+      .join(',');
+    const cursor = opts.cursor === undefined
+      ? null
+      : this.parseCursor(opts.cursor, sort);
+    return { orderBy: Object.fromEntries(orderBy), sort, cursor };
+  }
+
+  private getCursorOrderBy(orderBy: any): [string, 'asc' | 'desc'][] {
+    const entries = (Array.isArray(orderBy) ? orderBy : [orderBy]).flatMap(
+      (part) => Object.entries(part || {}),
+    ) as [string, any][];
+    const idField = this.crudConfig.id_field;
+    if (!entries.some(([field]) => field === idField)) {
+      entries.push([idField, 'asc']);
+    }
+    return entries.map(([field, direction]) => {
+      const normalized = direction?.toString().toLowerCase();
+      if (normalized !== 'asc' && normalized !== 'desc') {
+        throw new BadRequestException('cursor pagination requires asc or desc orderBy directions');
+      }
+      return [field, normalized];
+    });
+  }
+
+  private parseCursor(cursor: string, expectedSort: string) {
+    let value: Record<string, any>;
+    try {
+      value = JSON.parse(Buffer.from(cursor, 'base64').toString('utf8'));
+    } catch {
+      throw new BadRequestException('invalid cursor');
+    }
+    if (!value || typeof value !== 'object' || value.__sort !== expectedSort) {
+      throw new BadRequestException('cursor sort does not match orderBy');
+    }
+    if (!(this.crudConfig.id_field in value)) {
+      throw new BadRequestException('cursor is missing the entity ID');
+    }
+    return value;
+  }
+
+  private getCursorQuery(
+    pagination: ReturnType<CrudService<T>['getCursorPagination']>,
+    cursor: Record<string, any>,
+  ) {
+    return {
+      $or: pagination.orderBy.map(([field, direction], index) => ({
+        $and: [
+          ...pagination.orderBy
+            .slice(0, index)
+            .map(([previousField]) => ({ [previousField]: cursor[previousField] })),
+          { [field]: { [direction === 'asc' ? '$gt' : '$lt']: cursor[field] } },
+        ],
+      })),
+    };
+  }
+
+  private createCursor(
+    entity: T,
+    pagination: ReturnType<CrudService<T>['getCursorPagination']>,
+  ) {
+    const cursor = Object.fromEntries(
+      pagination.orderBy.map(([field]) => [field, entity[field]]),
+    );
+    cursor.__sort = pagination.sort;
+    return Buffer.from(JSON.stringify(cursor)).toString('base64');
+  }
