  async $unsecure_fastCreate(
    newEntity: Partial<T>,
    ctx: CrudContext<T>,
    inheritance?: Inheritance,
  ) {
    return await this.$create(
      newEntity,
      ctx,
      {
        em: null,
        noFlush: false,
        secure: false,
        options: { skipServiceHooks: true },
      },
      inheritance,
    );
